  <svg viewBox="0 0 700 320" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="26" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">Täglicher SOL-Fluss: Emission vs Burn (vor/nach SIMD-553)</text>
    <line x1="60" y1="250" x2="670" y2="250" stroke="#3f3f46"/>
    <rect x="110" y="70" width="90" height="180" fill="#f87171"/>
    <rect x="320" y="248" width="90" height="2" fill="#a1a1aa"/>
    <rect x="530" y="228" width="90" height="22" fill="#14f195"/>
    <text x="155" y="60" fill="#f87171" font-size="13" font-weight="700" text-anchor="middle" font-family="sans-serif">~60.000</text>
    <text x="365" y="240" fill="#a1a1aa" font-size="12" font-weight="700" text-anchor="middle" font-family="sans-serif">~648</text>
    <text x="575" y="218" fill="#14f195" font-size="13" font-weight="700" text-anchor="middle" font-family="sans-serif">~7.500–9.000</text>
    <text x="155" y="270" fill="#a1a1aa" font-size="11" text-anchor="middle" font-family="sans-serif">tägliche Inflationsemission</text>
    <text x="365" y="270" fill="#a1a1aa" font-size="11" text-anchor="middle" font-family="sans-serif">aktueller Burn</text>
